package main

import (
    "errors"
    "sync"
)

type Bank struct {
    accounts map[string]int
    mu       sync.RWMutex
}

func NewBank() *Bank {
    return &Bank{
        accounts: make(map[string]int),
    }
}

func (b *Bank) CreateAccount(accountID string, initialBalance int) error {
    b.mu.Lock()
    defer b.mu.Unlock()

    if _, exists := b.accounts[accountID]; exists {
        return errors.New("account already exists")
    }

    b.accounts[accountID] = initialBalance
    return nil
}

func (b *Bank) GetBalance(accountID string) (int, error) {
    b.mu.RLock()
    defer b.mu.RUnlock()

    balance, exists := b.accounts[accountID]
    if !exists {
        return 0, errors.New("account not found")
    }

    return balance, nil
}

func (b *Bank) Deposit(accountID string, amount int) error {
    if amount <= 0 {
        return errors.New("deposit amount must be positive")
    }

    b.mu.Lock()
    defer b.mu.Unlock()

    balance, exists := b.accounts[accountID]
    if !exists {
        return errors.New("account not found")
    }

    b.accounts[accountID] = balance + amount
    return nil
}

func (b *Bank) Withdraw(accountID string, amount int) error {
    if amount <= 0 {
        return errors.New("withdrawal amount must be positive")
    }

    b.mu.Lock()
    defer b.mu.Unlock()

    balance, exists := b.accounts[accountID]
    if !exists {
        return errors.New("account not found")
    }

    if balance < amount {
        return errors.New("insufficient funds")
    }

    b.accounts[accountID] = balance - amount
    return nil
}

func (b *Bank) Transfer(fromAccount, toAccount string, amount int) error {
    if amount <= 0 {
        return errors.New("transfer amount must be positive")
    }

    b.mu.Lock()
    defer b.mu.Unlock()

    fromBalance, fromExists := b.accounts[fromAccount]
    if !fromExists {
        return errors.New("source account not found")
    }

    _, toExists := b.accounts[toAccount]
    if !toExists {
        return errors.New("destination account not found")
    }

    if fromBalance < amount {
        return errors.New("insufficient funds")
    }

    b.accounts[fromAccount] = fromBalance - amount
    b.accounts[toAccount] = b.accounts[toAccount] + amount
    return nil
}